EventAction_LuaScript.ScriptText:
function spawn_plane()
Plane = ScenEdit_AddUnit( {type='Aircraft', unitname='Plane', loadoutid=8060, dbid=711, side='Red', lat='N54.12.53', lon='E21.03.41', altitude='30000'}) Plane.course ={{lat='N65.07.15', lon='E26.41.57'}}
--9th: Mission ScenEdit_AddMission('Red', 'Patrol_ASuW', 'Patrol', {type= 'Naval',Zone={'EP1', 'EP2', 'EP3', 'EP4'}}) ScenEdit_AssignUnitToMission('Plane', 'Patrol_ASuW') end
spawn_plane()
